export async function exportarInformeExcelAction(
    fechaDesde: string,
    fechaHasta: string,
    empresaId?: string | null,
    clienteId?: string | null,
    empresaNombre?: string | null,
    clienteNombre?: string | null
) {
    try {
        const [kpis, , topClientes, desgloseIVA] = await Promise.all([
            getKPIsAction(fechaDesde, fechaHasta, empresaId ?? undefined, clienteId ?? undefined),
            getEvolucionFacturacionAction(fechaDesde, fechaHasta, empresaId, clienteId),
            getTopClientesAction(fechaDesde, fechaHasta, 50, empresaId, clienteId),
            getDesgloseIVAAction(fechaDesde, fechaHasta, empresaId, clienteId),
        ])

        const workbook = new ExcelJS.Workbook()
        workbook.creator = `${clientConfig.nombreCorto} ERP`
        workbook.created = new Date()

        // Hoja 0: Resumen del informe (filtros aplicados) - como SAP, Oracle, Power BI
        const descPeriodo = describirPeriodo(fechaDesde, fechaHasta)
        const fechaDesdeFmt = format(new Date(fechaDesde), "d 'de' MMMM 'de' yyyy", { locale: es })
        const fechaHastaFmt = format(new Date(fechaHasta), "d 'de' MMMM 'de' yyyy", { locale: es })
        const ahora = format(new Date(), "d/MM/yyyy HH:mm:ss", { locale: es })

        const sheetResumen = workbook.addWorksheet('Resumen del informe')
        sheetResumen.columns = [{ width: 28 }, { width: 45 }]
        sheetResumen.addRow([])
        sheetResumen.addRow(['Informe de ventas', `${clientConfig.nombreCorto} ERP`]).getCell(1).font = { bold: true, size: 14 }
        sheetResumen.addRow([])
        sheetResumen.addRow(['Filtros aplicados', '']).getCell(1).font = { bold: true }
        sheetResumen.addRow(['Período', `${fechaDesdeFmt} – ${fechaHastaFmt}`])
        sheetResumen.addRow(['Descripción del período', descPeriodo])
        sheetResumen.addRow(['Empresa', empresaId ? (empresaNombre || empresaId) : 'Todas las empresas (Visión global)'])
        sheetResumen.addRow(['Cliente', clienteId ? (clienteNombre || clienteId) : 'Todos los clientes'])
        sheetResumen.addRow([])
        sheetResumen.addRow(['Fecha de generación', ahora])

        // Hoja 1: KPIs
        const sheetKPIs = workbook.addWorksheet('KPIs')
        sheetKPIs.columns = [
            { header: 'Métrica', key: 'metrica', width: 30 },
            { header: 'Valor Actual', key: 'actual', width: 20 },
            { header: 'Valor Anterior', key: 'anterior', width: 20 },
            { header: 'Variación', key: 'variacion', width: 15 },
        ]

        if (kpis.success && kpis.data) {
            sheetKPIs.addRow({
                metrica: 'Facturación Total',
                actual: `${kpis.data.actual.facturacion_total.toFixed(2)}€`,
                anterior: `${kpis.data.anterior.facturacion_total.toFixed(2)}€`,
                variacion: `${kpis.data.variaciones.facturacion}%`,
            })
            sheetKPIs.addRow({
                metrica: 'Número de Facturas',
                actual: kpis.data.actual.num_facturas,
                anterior: kpis.data.anterior.num_facturas,
                variacion: kpis.data.variaciones.facturas,
            })
            sheetKPIs.addRow({
                metrica: 'Ticket Medio',
                actual: `${kpis.data.actual.ticket_medio.toFixed(2)}€`,
                anterior: `${kpis.data.anterior.ticket_medio.toFixed(2)}€`,
                variacion: `${kpis.data.variaciones.ticket_medio}%`,
            })
        }

        // Hoja 2: Top Clientes
        const sheetClientes = workbook.addWorksheet('Top Clientes')
        sheetClientes.columns = [
            { header: 'Cliente', key: 'cliente', width: 40 },
            { header: 'Facturación', key: 'facturacion', width: 20 },
            { header: 'Nº Facturas', key: 'num_facturas', width: 15 },
        ]

        if (topClientes.success && topClientes.data) {
            topClientes.data.forEach((cliente: TopClienteData) => {
                sheetClientes.addRow({
                    cliente: cliente.cliente_nombre,
                    facturacion: `${cliente.facturacion.toFixed(2)}€`,
                    num_facturas: cliente.num_facturas,
                })
            })
        }

        // Hoja 3: Desglose IVA
        const sheetIVA = workbook.addWorksheet('Desglose IVA')
        sheetIVA.columns = [
            { header: 'Tipo IVA %', key: 'tipo_iva', width: 12 },
            { header: 'Base imponible', key: 'base', width: 18 },
            { header: 'Cuota IVA', key: 'cuota', width: 18 },
            { header: 'Total', key: 'total', width: 18 },
            { header: '% del total', key: 'porcentaje', width: 14 },
        ]
        if (desgloseIVA.success && desgloseIVA.data) {
            desgloseIVA.data.forEach((row: DesgloseIVAData) => {
                sheetIVA.addRow({
                    tipo_iva: `${row.tipo_iva}%`,
                    base: row.base_imponible.toFixed(2),
                    cuota: row.cuota_iva.toFixed(2),
                    total: row.total.toFixed(2),
                    porcentaje: `${row.porcentaje_del_total}%`,
                })
            })
        }

        // Generar buffer
        const buffer = await workbook.xlsx.writeBuffer()

        // Convertir a base64 para enviar al cliente
        const base64 = Buffer.from(buffer).toString('base64')

        return { success: true, data: base64 }
    } catch (error: unknown) {
        console.error('[exportarInformeExcelAction]', error)
        return { success: false, error: getErrorMessage(error) }
    }
}

import { NextResponse } from 'next/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'

const DEFAULT_PAGE_SIZE = 25
const MAX_PAGE_SIZE = 100

/**
 * GET /api/clientes/search?q=texto&page=1&limit=50&empresa_id=uuid
 * Devuelve clientes paginados. Si q está vacío, lista todos (ordenados por nombre).
 * Respeta el contexto de empresa del usuario (si es global, devuelve todos).
 * Opcional: empresa_id filtra por clientes asociados a esa empresa (para informes).
 * Responde: { items: ClienteOption[], total: number, page: number, totalPages: number }
 */
export async function GET(request: Request) {
    const { searchParams } = new URL(request.url)
    const q = sanitizeSearchInput(searchParams.get('q'))
    const page = Math.max(1, parseInt(searchParams.get('page') || '1', 10))
    const limit = Math.min(MAX_PAGE_SIZE, Math.max(1, parseInt(searchParams.get('limit') || String(DEFAULT_PAGE_SIZE), 10)))
    const from = (page - 1) * limit
    const to = from + limit - 1
    const empresaIdParam = searchParams.get('empresa_id') || null

    try {
        const adminClient = createAdminClient()
        const ctx = await getUserContext()
        const { empresaId: contextEmpresaId, empresas, isAdmin } = ctx

        // SEC-012: Validar que empresa_id del query pertenece al usuario
        let empresaId = empresaIdParam || contextEmpresaId
        if (empresaIdParam) {
            const tieneAcceso = isAdmin || (empresas as { empresa_id?: string }[]).some((e) => e.empresa_id === empresaIdParam)
            if (!tieneAcceso) {
                return NextResponse.json({ items: [], total: 0, page: 1, totalPages: 0 }, { status: 403 })
            }
        }

        let query = adminClient
            .from('clientes')
            .select('id, nombre_fiscal, nombre_comercial, cif', { count: 'exact' })
            .order('nombre_fiscal', { ascending: true })
            .range(from, to)

        if (q.length >= 1) {
            query = query.or(`nombre_fiscal.ilike.%${q}%,nombre_comercial.ilike.%${q}%,cif.ilike.%${q}%`)
        }

        // Excluir clientes de tests E2E (solo clientes reales)
        query = query.not('nombre_fiscal', 'ilike', '%e2e%')

        if (empresaId) {
            const adminSb = createAdminClient()
            const { data: ceRows } = await (adminSb.from as any)('clientes_empresas')
                .select('cliente_id')
                .eq('empresa_id', empresaId)
            const ids = (ceRows || []).map((r: { cliente_id: string }) => r.cliente_id)
            if (ids.length === 0) {
                return NextResponse.json({ items: [], total: 0, page: 1, totalPages: 0 })
            }
            query = query.in('id', ids)
        }

        const { data, error, count } = await query
        if (error) return NextResponse.json({ items: [], total: 0, page: 1, totalPages: 0 }, { status: 500 })

        const total = count ?? 0
        const totalPages = Math.ceil(total / limit)

        return NextResponse.json({
            items: (data || []).map((c: any) => ({
                id: c.id,
                label: c.nombre_fiscal || c.nombre_comercial || c.cif || c.id,
                cif: c.cif,
            })),
            total,
            page,
            totalPages,
        })
    } catch {
        return NextResponse.json({ items: [], total: 0, page: 1, totalPages: 0 }, { status: 500 })
    }
}

/**
 * GET /api/dev/save-pdf-factura
 * Genera el PDF de una factura emitida y lo guarda en temp-factura.pdf en la raíz del proyecto.
 * Solo para desarrollo. Query: ?id=<factura_id> (opcional; si no se pasa, usa la primera factura emitida).
 */
import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import { renderToStream } from '@react-pdf/renderer'
import { FacturaPdfDocument } from '@/components/ventas/pdf/pdf-document'
import type { Empresa, PdfOptions } from '@/components/ventas/pdf/pdf-document'
import React from 'react'
import path from 'path'
import fs from 'fs'
import { clientConfig } from '@/config/clients'

async function streamToBuffer(stream: NodeJS.ReadableStream): Promise<Buffer> {
  const chunks: Uint8Array[] = []
  return new Promise((resolve, reject) => {
    stream.on('data', (chunk) => chunks.push(chunk))
    stream.on('error', reject)
    stream.on('end', () => resolve(Buffer.concat(chunks)))
  })
}

export async function GET(request: Request) {
  if (process.env.NODE_ENV === 'production') {
    return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
  }

  const { searchParams } = new URL(request.url)
  const facturaId = searchParams.get('id')

  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )

  let query = supabase
    .from('facturas')
    .select('*, cliente:clientes(*), lineas:lineas_factura(*)')
    .in('estado', ['emitida', 'pagada'])

  if (facturaId) query = query.eq('id', facturaId)
  query = query.limit(1)

  const { data: facturas, error } = await query

  if (error || !facturas?.length) {
    return NextResponse.json({ error: 'No se encontró factura' }, { status: 404 })
  }

  const factura = facturas[0] as any

  try {
    const { data: empresaRow } = await supabase
      .from('empresas')
      .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, provincia, pais, cif, email, iban, banco, pie_factura')
      .eq('id', factura.empresa_id)
      .single()

    const empresa: Empresa = empresaRow ? {
      nombre_fiscal: empresaRow.razon_social || empresaRow.nombre_comercial || 'Empresa',
      direccion: empresaRow.direccion || '',
      ciudad: empresaRow.ciudad || '',
      codigo_postal: empresaRow.codigo_postal || '',
      cif: empresaRow.cif || '',
      email: empresaRow.email || undefined,
      iban: empresaRow.iban || undefined,
      banco: empresaRow.banco || undefined,
      pie_factura: empresaRow.pie_factura || undefined,
    } : {
      nombre_fiscal: 'Empresa',
      direccion: '',
      ciudad: '',
      codigo_postal: '',
      cif: '',
    }

    const fullFactura = { ...factura, descuento_tipo: factura.descuento_tipo as 'porcentaje' | 'fijo' | null }
    const EMPRESA_VILLEGAS_ID = '4b77324c-a10e-4714-b0a4-df4b9c5f6ca5'
    const EMPRESA_YENIFER_ID = 'e9a30c7d-eb2a-4c7a-91a6-a8bfe8f2278a'
    const EMPRESA_EDISON_ID = 'af15f25a-7ade-4de8-9241-a42e1b8407da'
    let pdfPlantilla: 'estandar' | 'premium' = 'estandar'
    let incluirLogoPdf = false
    if (factura.empresa_id === EMPRESA_VILLEGAS_ID) {
      pdfPlantilla = 'premium'
      incluirLogoPdf = true
    } else if (factura.empresa_id === EMPRESA_YENIFER_ID || factura.empresa_id === EMPRESA_EDISON_ID) {
      pdfPlantilla = 'estandar'
      incluirLogoPdf = false
    } else {
      pdfPlantilla = 'estandar'
      incluirLogoPdf = true
    }
    const pdfOptions: PdfOptions = {
      plantilla: pdfPlantilla,
      idioma: 'es',
      incluirLogo: incluirLogoPdf,
      incluirDatosBancarios: true,
      notasPie: '',
      colorAcento: '#0f172a',
    }

    let logoUrl: string | undefined
    if (incluirLogoPdf) {
      try {
        const logoPath = path.join(process.cwd(), 'public', clientConfig.logoPath.replace(/^\//, ''))
        if (fs.existsSync(logoPath)) {
          logoUrl = `data:image/png;base64,${fs.readFileSync(logoPath).toString('base64')}`
        }
      } catch {}
    }

    const stream = await renderToStream(
      React.createElement(FacturaPdfDocument as any, {
        factura: fullFactura,
        empresa,
        options: pdfOptions,
        logoUrl,
      }) as any
    )
    const pdfBuffer = await streamToBuffer(stream as any)

    const filename = `Factura-${factura.serie || 'FAC'}-${factura.numero}.pdf`
    const tempPath = path.join(process.cwd(), 'temp-factura.pdf')
    fs.writeFileSync(tempPath, pdfBuffer)

    return NextResponse.json({
      ok: true,
      path: tempPath,
      filename,
      factura: `${factura.serie}-${factura.numero}`,
    })
  } catch (e: any) {
    console.error(e)
    return NextResponse.json({ error: e.message }, { status: 500 })
  }
}

/**
 * API de desarrollo: sube un PDF de prueba y actualiza la factura externa
 * para poder emitirla. Solo en desarrollo.
 *
 * GET /api/dev/seed-factura-externa?id=FACTURA_ID
 */
import { createServerClient } from '@/lib/supabase/server'
import { NextResponse } from 'next/server'
import { getUserContext } from '@/app/actions/usuarios-empresas'

const MINIMAL_PDF = Buffer.from(
    '%PDF-1.4\n1 0 obj<</Type/Catalog/Pages 2 0 R>>endobj\n2 0 obj<</Type/Pages/Kids[3 0 R]/Count 1>>endobj\n3 0 obj<</Type/Page/MediaBox[0 0 612 792]/Parent 2 0 R>>endobj\nxref\n0 4\n0000000000 65535 f \n0000000009 00000 n \n0000000058 00000 n \n0000000115 00000 n \ntrailer<</Size 4/Root 1 0 R>>\nstartxref\n190\n%%EOF\n',
    'utf-8'
)

export async function GET(request: Request) {
    if (process.env.NODE_ENV === 'production') {
        return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
    }

    const { searchParams } = new URL(request.url)
    const facturaId = searchParams.get('id')
    if (!facturaId) {
        return NextResponse.json({ error: 'Falta id de factura (query param id)' }, { status: 400 })
    }

    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return NextResponse.json({ error: 'No autenticado' }, { status: 401 })
    }

    const { empresaId, rol } = await getUserContext()
    const isGlobal = !empresaId && rol === 'admin'

    let query = supabase
        .from('facturas')
        .select('id, empresa_id, es_externa')
        .eq('id', facturaId)
        .eq('es_externa', true)
    if (!isGlobal && empresaId) query = query.eq('empresa_id', empresaId)
    const { data: factura } = await query.single()

    if (!factura) {
        return NextResponse.json({ error: 'Factura externa no encontrada' }, { status: 404 })
    }

    const fileName = `facturas/${facturaId}_${Date.now()}.pdf`

    const { error: uploadError } = await supabase.storage
        .from('facturas-externas')
        .upload(fileName, MINIMAL_PDF, {
            contentType: 'application/pdf',
            upsert: true
        })

    if (uploadError) {
        return NextResponse.json({ error: `Error subiendo PDF: ${uploadError.message}` }, { status: 500 })
    }

    const { data: { publicUrl } } = supabase.storage
        .from('facturas-externas')
        .getPublicUrl(fileName)

    const { error: updateError } = await supabase
        .from('facturas')
        .update({ archivo_url: publicUrl } as any)
        .eq('id', facturaId)

    if (updateError) {
        return NextResponse.json({ error: `Error actualizando: ${updateError.message}` }, { status: 500 })
    }

    return NextResponse.json({
        success: true,
        archivo_url: publicUrl,
        message: 'PDF subido. Puedes emitir la factura desde la UI.'
    })
}

