import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import { resend } from '@/lib/email/resend'
import { renderToStream } from '@react-pdf/renderer'
import { FacturaPdfDocument } from '@/components/ventas/pdf/pdf-document'
import type { Empresa, PdfOptions } from '@/components/ventas/pdf/pdf-document'
import React from 'react'
import path from 'path'
import fs from 'fs'
import { clientConfig } from '@/config/clients'

async function streamToBuffer(stream: NodeJS.ReadableStream): Promise<Buffer> {
  const chunks: Uint8Array[] = []
  return new Promise((resolve, reject) => {
    stream.on('data', (chunk) => chunks.push(chunk))
    stream.on('error', reject)
    stream.on('end', () => resolve(Buffer.concat(chunks)))
  })
}

export async function POST(request: Request) {
  if (process.env.NODE_ENV === 'production') {
    return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
  }

  const body = await request.json().catch(() => ({}))
  const to = (body.to as string) || 'j.e.bolanos@hotmail.com'

  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )

  const { data: empresas } = await supabase.from('empresas').select('id, razon_social').limit(10)
  if (!empresas?.length) {
    return NextResponse.json({ error: 'No hay empresas' }, { status: 400 })
  }

  const results: { factura: string; empresa: string; ok: boolean; id?: string; error?: string }[] = []
  const seenEmpresas = new Set<string>()

  for (const emp of empresas) {
    if (seenEmpresas.has(emp.id)) continue

    const { data: facturas } = await supabase
      .from('facturas')
      .select('*, cliente:clientes(*), lineas:lineas_factura(*)')
      .eq('empresa_id', emp.id)
      .in('estado', ['emitida', 'pagada'])
      .limit(1)

    if (!facturas?.length) continue

    const factura = facturas[0] as any
    try {
      const { data: empresaRow } = await supabase
        .from('empresas')
        .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, provincia, pais, cif, email, iban, banco, pie_factura')
        .eq('id', factura.empresa_id)
        .single()

      const empresa: Empresa = empresaRow ? {
        nombre_fiscal: empresaRow.razon_social || empresaRow.nombre_comercial || 'Empresa',
        direccion: empresaRow.direccion || '',
        ciudad: empresaRow.ciudad || '',
        codigo_postal: empresaRow.codigo_postal || '',
        cif: empresaRow.cif || '',
        email: empresaRow.email || undefined,
        iban: empresaRow.iban || undefined,
        banco: empresaRow.banco || undefined,
        pie_factura: empresaRow.pie_factura || undefined,
      } : {
        nombre_fiscal: 'Empresa',
        direccion: '',
        ciudad: '',
        codigo_postal: '',
        cif: '',
      }

      const fullFactura = { ...factura, descuento_tipo: factura.descuento_tipo as 'porcentaje' | 'fijo' | null }
      const EMPRESA_VILLEGAS_ID = '4b77324c-a10e-4714-b0a4-df4b9c5f6ca5'
      const EMPRESA_YENIFER_ID = 'e9a30c7d-eb2a-4c7a-91a6-a8bfe8f2278a'
      const EMPRESA_EDISON_ID = 'af15f25a-7ade-4de8-9241-a42e1b8407da'
      let pdfPlantilla: 'estandar' | 'premium' = 'estandar'
      let incluirLogoPdf = false
      if (factura.empresa_id === EMPRESA_VILLEGAS_ID) {
        pdfPlantilla = 'premium'
        incluirLogoPdf = true
      } else if (factura.empresa_id === EMPRESA_YENIFER_ID || factura.empresa_id === EMPRESA_EDISON_ID) {
        pdfPlantilla = 'estandar'
        incluirLogoPdf = false
      } else {
        pdfPlantilla = 'estandar'
        incluirLogoPdf = true
      }
      const pdfOptions: PdfOptions = {
        plantilla: pdfPlantilla,
        idioma: 'es',
        incluirLogo: incluirLogoPdf,
        incluirDatosBancarios: true,
        notasPie: '',
        colorAcento: '#0f172a',
      }

      let logoUrl: string | undefined
      if (incluirLogoPdf) {
        try {
          const logoPath = path.join(process.cwd(), 'public', clientConfig.logoPath.replace(/^\//, ''))
          if (fs.existsSync(logoPath)) {
            logoUrl = `data:image/png;base64,${fs.readFileSync(logoPath).toString('base64')}`
          }
        } catch {}
      }

      const stream = await renderToStream(
        // @ts-ignore - React 19 typings conflict with @react-pdf/renderer
        React.createElement(FacturaPdfDocument, {
          factura: fullFactura,
          empresa,
          options: pdfOptions,
          logoUrl,
        })
      )
      const pdfBuffer = await streamToBuffer(stream as any)

      const empresaNombre = empresaRow?.razon_social || empresaRow?.nombre_comercial || clientConfig.nombre
      const subject = `Factura ${factura.serie || 'FAC'}-${factura.numero} - ${empresaNombre}`
      const message = `Estimado cliente,\n\nAdjuntamos la factura ${factura.serie}-${factura.numero} correspondiente a los servicios prestados.\n\nQuedamos a su disposición para cualquier consulta.\n\nAtentamente,\n${clientConfig.nombre}`

      const { data, error } = await resend.emails.send({
        from: process.env.RESEND_FROM || clientConfig.email.from,
        to,
        subject,
        html: `<p>${message.replace(/\n/g, '<br/>')}</p>`,
        attachments: [{
          filename: `Factura-${factura.serie || 'FAC'}-${factura.numero}.pdf`,
          content: pdfBuffer,
          contentType: 'application/pdf',
        }],
      })

      if (error) throw new Error(error.message)
      results.push({ factura: `${factura.serie}-${factura.numero}`, empresa: emp.razon_social, ok: true, id: data?.id })
      seenEmpresas.add(emp.id)
    } catch (e: any) {
      results.push({
        factura: `${factura.serie}-${factura.numero}`,
        empresa: emp.razon_social,
        ok: false,
        error: e.message,
      })
    }
  }

  return NextResponse.json({ to, results })
}

import { createServerClient } from '@/lib/supabase/server'
import { renderToStream } from '@react-pdf/renderer'
import { DatosFiscalesPdfDocument } from '@/components/ventas/pdf/datos-fiscales-pdf'
import { NextResponse } from 'next/server'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import type { Empresa } from '@/types/empresa'
import * as React from 'react'

/**
 * GET /api/empresas/datos-fiscales/pdf
 * Genera un PDF con los datos fiscales de la empresa activa del usuario.
 * Opcionalmente acepta ?empresa_id=UUID para especificar una empresa concreta
 * (debe estar en las empresas del usuario).
 */
export async function GET(request: Request) {
    const { searchParams } = new URL(request.url)
    const empresaIdParam = searchParams.get('empresa_id')

    const supabase = await createServerClient()
    const {
        data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
        return new NextResponse('Unauthorized', { status: 401 })
    }

    const { empresaId: empresaActivaId, empresas } = await getUserContext()

    // Resolver empresa_id: parámetro de query > empresa activa
    let empresaId = empresaIdParam || empresaActivaId

    // Validar que el usuario tiene acceso a esa empresa
    // empresas son filas de usuarios_empresas: tienen empresa_id y opcionalmente empresa.id
    if (empresaId) {
        const tieneAcceso = empresas.some(
            (e: { empresa_id?: string; empresa?: { id?: string } }) =>
                e.empresa_id === empresaId || (e.empresa && e.empresa.id === empresaId)
        )
        if (!tieneAcceso) {
            // Usuario puede tener solo perfil (sin usuarios_empresas): comprobar perfil.empresa_id
            const { data: perfil } = await supabase
                .from('perfiles')
                .select('empresa_id')
                .eq('user_id', user.id)
                .single()
            if (perfil?.empresa_id !== empresaId) {
                return new NextResponse('Forbidden', { status: 403 })
            }
        }
    }

    // Fallback: si no hay empresa activa por contexto, usar la del perfil
    if (!empresaId) {
        const { data: perfil } = await supabase
            .from('perfiles')
            .select('empresa_id')
            .eq('user_id', user.id)
            .single()
        empresaId = perfil?.empresa_id || null
    }

    if (!empresaId) {
        return new NextResponse('No empresa activa. Selecciona una empresa en el header.', { status: 400 })
    }

    // Cargar todos los datos de la empresa
    const { data: empresaData, error } = await supabase
        .from('empresas')
        .select('*')
        .eq('id', empresaId)
        .single()

    if (error || !empresaData) {
        return new NextResponse('Empresa no encontrada', { status: 404 })
    }

    const empresa = empresaData as unknown as Empresa

    // Resolver el logo: intentar desde logo_url de la empresa (Supabase Storage)
    let logoUrl: string | undefined
    if (empresa.logo_url) {
        try {
            const res = await fetch(empresa.logo_url)
            if (res.ok) {
                const buf = Buffer.from(await res.arrayBuffer())
                const mime = res.headers.get('content-type') || 'image/png'
                logoUrl = `data:${mime};base64,${buf.toString('base64')}`
            }
        } catch {
            // Si no se puede cargar el logo, continuar sin él
        }
    }

    // Generar PDF
    try {
        const stream = await renderToStream(
            React.createElement(DatosFiscalesPdfDocument as any, {
                empresa,
                logoUrl,
            }) as any
        )

        const nombreArchivo = `Datos-fiscales-${empresa.razon_social.replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '-')}.pdf`
        const nombreEncoded = encodeURIComponent(nombreArchivo)

        return new NextResponse(stream as any, {
            headers: {
                'Content-Type': 'application/pdf',
                'Content-Disposition': `attachment; filename="${nombreArchivo}"; filename*=UTF-8''${nombreEncoded}`,
            },
        })
    } catch (err: any) {
        console.error('Error generando PDF de datos fiscales:', err)
        return new NextResponse(`Error generando PDF: ${err.message}`, { status: 500 })
    }
}

import { createServerClient } from '@/lib/supabase/server'
import { renderToStream } from '@react-pdf/renderer'
import { FacturaPdfDocument, type Empresa, type PdfOptions } from '@/components/ventas/pdf/pdf-document'
import { NextResponse } from 'next/server'
import path from 'path'
import fs from 'fs'
import { getUserContext } from '@/app/actions/usuarios-empresas'

import { clientConfig } from '@/config/clients'

export async function GET(
    request: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params
    const { searchParams } = new URL(request.url)

    let plantillaOpt = (searchParams.get('plantilla') as any) || null

    const supabase = await createServerClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return new NextResponse('Unauthorized', { status: 401 })
    }

    const { empresaId, rol } = await getUserContext()
    const isGlobal = !empresaId && rol === 'admin'

    const { data: perfil } = await supabase
        .from('perfiles')
        .select('empresa_id')
        .eq('user_id', user.id)
        .single()

    const empresaFiltro = isGlobal ? undefined : (empresaId || perfil?.empresa_id)
    if (!empresaFiltro && !isGlobal) {
        return new NextResponse('No company assigned', { status: 403 })
    }

    let query = supabase
        .from('facturas')
        .select(`
            *,
            cliente:clientes(*),
            lineas:lineas_factura(*)
        `)
        .eq('id', id)
    if (empresaFiltro) query = query.eq('empresa_id', empresaFiltro)
    const { data: factura, error } = await query.single()

    if (error || !factura) {
        return new NextResponse('Invoice not found', { status: 404 })
    }

    // PLANTILLA LOGIC (RFC-025 override)
    // If no query param provided, check DB invoice template
    if (!plantillaOpt && factura.plantilla_pdf_id) {
        // Map DB ID to visual template option
        const PLANTILLA_CORPORATIVA_ID = '5e63ff58-2cd5-4234-805a-fd93f50ee84c'
        if (factura.plantilla_pdf_id === PLANTILLA_CORPORATIVA_ID) {
            plantillaOpt = 'premium'
        } else {
            plantillaOpt = 'estandar'
        }
    }

    // Default fallback
    const finalPlantilla = plantillaOpt || 'estandar'

    const options: PdfOptions = {
        plantilla: finalPlantilla as any,
        idioma: (searchParams.get('idioma') as any) || 'es',
        incluirLogo: searchParams.get('incluirLogo') === 'true',
        incluirDatosBancarios: searchParams.get('incluirDatosBancarios') === 'true',
        notasPie: searchParams.get('notasPie') || '',
        colorAcento: searchParams.get('colorAcento') || undefined,
    }

    // Fetch Empresa Data (emisor de la factura)
    const { data: empresaRow } = await supabase
        .from('empresas')
        .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, provincia, pais, cif, email, iban, banco, pie_factura, logo_url')
        .eq('id', factura.empresa_id)
        .single()

    const empresa: Empresa = empresaRow ? {
        nombre_fiscal: empresaRow.razon_social || empresaRow.nombre_comercial || 'Empresa',
        direccion: empresaRow.direccion || '',
        ciudad: empresaRow.ciudad || '',
        codigo_postal: empresaRow.codigo_postal || '',
        cif: empresaRow.cif || '',
        email: empresaRow.email || undefined,
        iban: empresaRow.iban || undefined,
        banco: empresaRow.banco || undefined,
        pie_factura: empresaRow.pie_factura || undefined,
    } : {
        nombre_fiscal: 'Empresa',
        direccion: '',
        ciudad: '',
        codigo_postal: '',
        cif: '',
    }

    // Load Logo dinámicamente desde el config del cliente
    let logoUrl: string | undefined
    try {
        const relativeLogoPath = clientConfig.logoPngPath || clientConfig.logoPath
        const logoPath = path.join(process.cwd(), 'public', relativeLogoPath.replace(/^\//, ''))
        if (fs.existsSync(logoPath)) {
            const logoBuffer = fs.readFileSync(logoPath)
            const isSvg = relativeLogoPath.endsWith('.svg')
            const mimeType = isSvg ? 'image/svg+xml' : 'image/png'
            logoUrl = `data:${mimeType};base64,${logoBuffer.toString('base64')}`
        } else {
            logoUrl = undefined
        }
    } catch (e) {
        console.warn('Could not load logo for PDF', e)
        logoUrl = undefined
    }

    // Generate Stream
    try {

        const stream = await renderToStream(
            <FacturaPdfDocument
                factura={factura as unknown as any}
                empresa={empresa}
                options={options}
                logoUrl={logoUrl}
            />
        )

        // Return PDF Response
        const filename = `${factura.serie}-${factura.numero}.pdf`
        return new NextResponse(stream as any, {
            headers: {
                'Content-Type': 'application/pdf',
                'Content-Disposition': `attachment; filename="${filename}"; filename*=UTF-8''${encodeURIComponent(filename)}`
            }
        })
    } catch (err: any) {
        console.error('PDF Generation Error Stack:', err.stack)
        return new NextResponse(`Error generating PDF: ${err.message}`, { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { createServerClient } from '@/lib/supabase/server'
import { getEmpresaAction, actualizarEmpresaAction } from '@/app/actions/empresa'
import { crearClienteAction, actualizarClienteAction } from '@/app/actions/clientes'
import { crearFacturaAction } from '@/app/actions/ventas'
import { registrarPagoAction } from '@/app/actions/pagos'
import { crearFacturaRectificativaAction, getRectificativasDeFacturaAction } from '@/app/actions/facturas-rectificativas'
import { getKPIsAction, getEvolucionFacturacionAction, exportarInformeExcelAction } from '@/app/actions/informes'

type TestResult = {
    name: string
    status: 'passed' | 'failed'
    message?: string
    duration?: number
    logs: string[]
}

export async function GET() {
    if (process.env.NODE_ENV === 'production') {
        return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
    }

    const results: TestResult[] = []

    // Helper to get invoice directly
    const getFactura = async (id: string) => {
        const supabase = await createServerClient()
        const { data } = await supabase.from('facturas').select('*').eq('id', id).single()
        return { data }
    }

    const runTest = async (name: string, fn: () => Promise<void>) => {
        const start = performance.now()
        const testLogs: string[] = []
        // eslint-disable-next-line @typescript-eslint/no-unused-vars
        const consoleLog = (msg: string) => testLogs.push(msg)

        try {
            await fn()
            results.push({
                name,
                status: 'passed',
                duration: performance.now() - start,
                logs: testLogs
            })
        } catch (error: unknown) {
            const msg = error instanceof Error ? error.message : String(error)
            results.push({
                name,
                status: 'failed',
                message: msg,
                duration: performance.now() - start,
                logs: testLogs
            })
        }
    }

    // --- EMPRESAS ---
    await runTest('Empresa: Get & Update', async () => {
        const res = await getEmpresaAction()
        if (!res.success) throw new Error(res.error)
        if (!res.data) throw new Error('No data')

        // Update
        const formData = new FormData()
        formData.append('razon_social', res.data.razon_social || 'Test Company')
        if (res.data.cif) formData.append('cif', res.data.cif)

        const update = await actualizarEmpresaAction(formData)
        if (!update.success) throw new Error(update.error)
    })

    // Helper to get client directly
    const getCliente = async (id: string) => {
        const supabase = await createServerClient()
        const { data } = await supabase.from('clientes').select('*').eq('id', id).single()
        return { success: true, data }
    }

    // Helper to search clients
    const buscarClientes = async (searchQuery: string) => {
        const { sanitizeSearchInput } = await import('@/lib/security/sanitize-search')
        const q = sanitizeSearchInput(searchQuery)
        const supabase = await createServerClient()
        const { data } = await supabase.from('clientes').select('*').ilike('nombre_fiscal', q ? `%${q}%` : '%')
        return { success: true, data }
    }

    // --- CLIENTES ---
    let clienteId = ''
    await runTest('Clientes: Modulo Completo', async () => {
        // 1. Create
        const uniqueCif = `B${Date.now().toString().slice(-8)}`

        const create = await crearClienteAction({
            nombre_fiscal: 'QA Test Client ' + Date.now(),
            cif: uniqueCif,
            email: 'qa@test.com',
            direccion: 'Test St',
            ciudad: 'Madrid',
            codigo_postal: '28001',
            tipo_persona: 'juridica',
            dias_vencimiento: '30',
            descuento_comercial: '0',
            iva_aplicable: '21',
            activo: 'on'
        } as any) // formData mocking

        if (create.success && create.data) {
            clienteId = create.data.id
        } else {
            // Fallback: create formData if logic expects it
            const fd = new FormData()
            fd.append('nombre_fiscal', 'QA Test Client ' + Date.now())
            fd.append('cif', uniqueCif)
            fd.append('email', 'qa@test.com')
            fd.append('activo', 'on')

            const createFd = await crearClienteAction(fd)
            if (!createFd.success || !createFd.data) throw new Error(createFd.error || 'Create failed no data')
            clienteId = createFd.data.id
        }

        if (!clienteId) throw new Error('Cliente ID not set')

        // 2. Get
        const get = await getCliente(clienteId)
        if (!get.data || get.data.cif !== uniqueCif) throw new Error('Get failed')

        // 3. Update
        const fd = new FormData()
        fd.append('ciudad', 'Barcelona')
        const update = await actualizarClienteAction(clienteId, fd)
        if (!update.success) throw new Error('Update failed')

        // 4. Search
        const search = await buscarClientes('QA Test')
        if (!search.success || !search.data || search.data.length === 0) throw new Error('Search failed')
    })

    // --- FACTURAS ---
    let facturaId = ''
    await runTest('Facturas: Flujo Completo', async () => {
        if (!clienteId) throw new Error('No clienteId from previous test')

        // 1. Get Series
        const supabase = await createServerClient()
        const { data: serie } = await supabase.from('series_facturacion').select('id').limit(1).single()
        const serieId = serie?.id

        if (!serieId) throw new Error('No series found in database')

        // 2. Create - Need FormData
        const fd = new FormData()
        fd.append('cliente_id', clienteId)
        fd.append('fecha_emision', new Date().toISOString().split('T')[0])
        fd.append('fecha_vencimiento', new Date(Date.now() + 86400000).toISOString().split('T')[0])
        fd.append('serie', serieId)
        fd.append('empresa_id', 'ignored') // Just in case schema validates presence

        // We need to match the JSON expectation of the action
        const lineas = [{ concepto: 'QA Test Item', cantidad: 1, precio_unitario: 100, iva: 21, descripcion: 'QA Test' }]
        fd.append('lineas', JSON.stringify(lineas))
        fd.append('subtotal', '100')
        fd.append('total', '121')
        fd.append('base_imponible', '100')
        fd.append('iva', '21')

        const create = await crearFacturaAction(fd)
        if (!create.success || !create.data) throw new Error(create.error || 'Create Invoice failed no data')
        facturaId = create.data.id
        if (!facturaId) throw new Error('Action success but no ID')

        // 3. Payment
        const fdPago = new FormData()
        fdPago.append('factura_id', facturaId)
        fdPago.append('importe', '121')
        fdPago.append('metodo_pago', 'transferencia')
        fdPago.append('fecha_pago', new Date().toISOString().split('T')[0])

        const pay = await registrarPagoAction(fdPago)
        if (!pay.success) throw new Error(pay.error)

        // 4. Check Status (It should be 'pagada' if paid fully)
        const check = await getFactura(facturaId)
        if (check.data?.estado !== 'pagada') throw new Error(`Estado incorrecto: ${check.data?.estado} expected pagada`)
    })

    // --- RECTIFICATIVAS ---
    await runTest('Rectificativas: Total con Abono', async () => {
        if (!facturaId) throw new Error('No facturaId')

        const rect = await crearFacturaRectificativaAction({
            factura_original_id: facturaId,
            tipo_rectificativa: 'total',
            motivo: 'QA Test Rectification Automatic -----------------',
            generar_abono: true
        })
        if (!rect.success) throw new Error(rect.error)

        const list = await getRectificativasDeFacturaAction(facturaId)
        if (!list.success || !list.data || list.data.length === 0) throw new Error('List rectificativas failed')
    })

    // --- INFORMES ---
    await runTest('Informes: KPIs & Data', async () => {
        const kpis = await getKPIsAction(new Date().toISOString(), new Date().toISOString())
        if (!kpis.success) throw new Error('KPIs failed')

        const evol = await getEvolucionFacturacionAction(
            new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString(),
            new Date().toISOString()
        )
        if (!evol.success) throw new Error('Evolucion failed')

        const excel = await exportarInformeExcelAction(
            new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString(),
            new Date().toISOString()
        )
        if (!excel.success) throw new Error('Excel failed')
    })

    // Clean up
    await runTest('Cleanup', async () => {
        if (clienteId) {
            // Typically we can't delete if related invoices exist depending on FK cascade.
            // But we can try soft delete or just skip.
            // await eliminarClienteAction(clienteId)
        }
    })

    return NextResponse.json({
        summary: {
            total: results.length,
            passed: results.filter(r => r.status === 'passed').length,
            failed: results.filter(r => r.status === 'failed').length
        },
        results
    })
}

import { NextRequest, NextResponse } from 'next/server'
import ExcelJS from 'exceljs'
import { format } from 'date-fns'
import { createAdminClient } from '@/lib/supabase/admin'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'
import { auditLog } from '@/lib/security/audit-log'
import { clientConfig } from '@/config/clients'

/** Formato numérico español */
function formatNumeroES(n: number): string {
    return new Intl.NumberFormat('es-ES', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(n)
}

export async function GET(request: NextRequest) {
    try {
        const { searchParams } = new URL(request.url)
        const formatType = searchParams.get('format') || 'xlsx'
        if (formatType !== 'xlsx' && formatType !== 'csv') {
            return NextResponse.json({ error: 'Formato no válido. Use format=xlsx o format=csv' }, { status: 400 })
        }

        const { empresaId, userId } = await getUserContext()
        auditLog('export_clientes', userId, { empresaId, format: formatType })
        const adminClient = createAdminClient()

        const search = sanitizeSearchInput(searchParams.get('search'))
        const estado = searchParams.get('estado') || 'todos'
        const orden = searchParams.get('orden') || 'nombre_asc'

        let orderField = 'nombre_fiscal'
        let orderAsc = true
        switch (orden) {
            case 'nombre_desc': orderField = 'nombre_fiscal'; orderAsc = false; break
            case 'cif_asc': orderField = 'cif'; orderAsc = true; break
            case 'cif_desc': orderField = 'cif'; orderAsc = false; break
            case 'facturacion_asc': orderField = 'total_facturado'; orderAsc = true; break
            case 'facturacion_desc': orderField = 'total_facturado'; orderAsc = false; break
            case 'estado_asc': orderField = 'activo'; orderAsc = true; break
            case 'estado_desc': orderField = 'activo'; orderAsc = false; break
            default: orderField = 'nombre_fiscal'; orderAsc = true; break
        }

        let query = adminClient.from('clientes').select('*')

        if (empresaId) {
            const { data: ces } = await (adminClient.from as any)('clientes_empresas')
                .select('cliente_id')
                .eq('empresa_id', empresaId)
            const clienteIds = (ces || []).map((c: { cliente_id: string }) => c.cliente_id)
            if (clienteIds.length > 0) {
                query = query.in('id', clienteIds)
            } else {
                query = query.eq('id', '00000000-0000-0000-0000-000000000000')
            }
        }

        if (search) {
            query = query.or(`nombre_fiscal.ilike.%${search}%,cif.ilike.%${search}%,nombre_comercial.ilike.%${search}%`)
        }
        if (estado === 'activos') query = query.eq('activo', true)
        if (estado === 'inactivos') query = query.eq('activo', false)

        query = query.order(orderField, { ascending: orderAsc, nullsFirst: false })

        const { data: clientesRaw, error } = await query

        if (error) {
            console.error('[clientes/export]', error)
            return NextResponse.json({ error: 'Error al obtener clientes' }, { status: 500 })
        }

        let clientes = (clientesRaw || []) as Array<Record<string, unknown> & { id: string; total_facturado?: number }>

        // Facturación por empresa cuando hay empresa seleccionada
        if (empresaId && clientes.length > 0) {
            const clienteIds = clientes.map((c) => c.id)
            const { data: facturas } = await adminClient
                .from('facturas')
                .select('cliente_id, total')
                .eq('empresa_id', empresaId)
                .in('cliente_id', clienteIds)
                .in('estado', ['emitida', 'vencida', 'parcial', 'pagada'])
            const totalPorCliente: Record<string, number> = {}
            for (const f of facturas || []) {
                totalPorCliente[f.cliente_id] = (totalPorCliente[f.cliente_id] || 0) + Number(f.total ?? 0)
            }
            clientes = clientes.map((c) => ({ ...c, total_facturado: totalPorCliente[c.id] ?? 0 }))
            if (orden === 'facturacion_asc' || orden === 'facturacion_desc') {
                const asc = orden === 'facturacion_asc'
                clientes = [...clientes].sort((a, b) => {
                    const ta = Number(a.total_facturado) || 0
                    const tb = Number(b.total_facturado) || 0
                    return asc ? ta - tb : tb - ta
                })
            }
        }

        const rows = clientes.map((c: Record<string, unknown>) => ({
            nombre: (c.nombre_fiscal as string) || '',
            cif: (c.cif as string) || '',
            email: (c.email_principal as string) || '',
            telefono: (c.telefono_principal as string) || '',
            ciudad: (c.ciudad as string) || '',
            facturacion: formatNumeroES(Number(c.total_facturado) || 0),
            estado: (c.activo as boolean) ? 'Activo' : 'Inactivo',
        }))

        const headers = ['Nombre', 'CIF', 'Email', 'Teléfono', 'Ciudad', 'Facturación', 'Estado']

        if (formatType === 'csv') {
            const csvRows = [headers.join(';'), ...rows.map((r) => Object.values(r).map((v) => `"${String(v).replace(/"/g, '""')}"`).join(';'))]
            const csv = '\ufeff' + csvRows.join('\n')
            return new NextResponse(csv, {
                headers: {
                    'Content-Type': 'text/csv; charset=utf-8',
                    'Content-Disposition': `attachment; filename="clientes-${format(new Date(), 'yyyy-MM-dd')}.csv"`,
                },
            })
        }

        const workbook = new ExcelJS.Workbook()
        workbook.creator = `${clientConfig.nombreCorto} ERP`
        const sheet = workbook.addWorksheet('Clientes')
        sheet.columns = [
            { header: 'Nombre', key: 'nombre', width: 35 },
            { header: 'CIF', key: 'cif', width: 14 },
            { header: 'Email', key: 'email', width: 30 },
            { header: 'Teléfono', key: 'telefono', width: 16 },
            { header: 'Ciudad', key: 'ciudad', width: 20 },
            { header: 'Facturación', key: 'facturacion', width: 16 },
            { header: 'Estado', key: 'estado', width: 10 },
        ]

        const headerRow = sheet.getRow(1)
        headerRow.font = { bold: true }
        headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE2E8EC' } }

        rows.forEach((r) => sheet.addRow(r))

        const buffer = await workbook.xlsx.writeBuffer()
        return new NextResponse(buffer, {
            headers: {
                'Content-Type': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                'Content-Disposition': `attachment; filename="clientes-${format(new Date(), 'yyyy-MM-dd')}.xlsx"`,
            },
        })
    } catch (err) {
        console.error('[clientes/export]', err)
        return NextResponse.json({ error: 'Error al exportar clientes' }, { status: 500 })
    }
}

'use client'

import { useState, useEffect, useCallback } from 'react'

function useIsMobile() {
    const [isMobile, setIsMobile] = useState(false)
    useEffect(() => {
        const mq = window.matchMedia('(max-width: 767px)')
        setIsMobile(mq.matches)
        const fn = () => setIsMobile(mq.matches)
        mq.addEventListener('change', fn)
        return () => mq.removeEventListener('change', fn)
    }, [])
    return isMobile
}
