                                    <Pie
                                        data={estados}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={55}
                                        outerRadius={85}
                                        paddingAngle={3}
                                        dataKey="cantidad"
                                        nameKey="estado"
                                        label={({ name, percent }: { name?: string; percent?: number }) =>
                                            `${estadoLabels[name || ''] || name || ''} ${((percent || 0) * 100).toFixed(0)}%`
                                        }
                                    >
                                        {estados.map((_, i) => (
                                            <Cell key={i} fill={COLORS[i % COLORS.length]} />
