        name: string
        href: string
        icon: any
    }[]
}

const navigation: NavItem[] = [
    {
        name: 'Dashboard',
        href: '/dashboard',
        icon: LayoutDashboard,
    },
    {
        name: 'Ventas',
        href: '/ventas',
